triggered := false
if ((#MultiButton).multiButton_button4 == "pushed") {
if (triggered == false) {
tmp = (#Light #LevelControl #LivingRoom).levelControl_currentLevel - 15
        if (tmp < 10) {
tmp = 10
}
(#Light #LevelControl #LivingRoom).levelControl_moveToLevel(tmp, 0)
        triggered = true
}
}
else {
triggered = false
}

